import type { Product } from "./types.ts";

// Intentionally omits `tags` to break conformance with Product
const brokenSchema = type.declare<Product>().type({
  id: "string",
  sku: "string",
  price: "number",
});

export default brokenSchema;

import productSchema from "./schema.ts";

const sample: unknown = {
  id: "prod-001",
  sku: "SKU-12345",
  price: 29.99,
  tags: ["electronics", "gadget"],
};

const result = productSchema(sample);
if (result instanceof productSchema.errors) {
  console.error("Validation failed:", result.summary);
  process.exit(1);
}

console.log(`Validated product: ${result.id}`);

